INSERT INTO `jobs` VALUES (1,'Business Development Manager','HL Solutions LLC','Hyderabad, IN','Hyderabad','IN',12.20,9.00,'INR','FULLTIME',8,15,'About HL Solutions : HL Solutions is a Boutique IT Staffing Partner specializing in Cloud, Data & AI, and Application Integration talent solutions. We collaborate with clients across diverse industries to deliver end-to-end staffing and executive search services designed to meet evolving technology needs. Whether it’s full-time placements, contract staffing, specialized technology training, or C-suite leadership hiring , HL Solutions serves as a trusted partner committed to excellence, speed, a…','adzuna','5661686045','2026-03-13 13:20:22',1,'https://www.adzuna.in/land/ad/5661686045?se=fBNAYt8e8RG_S--KZEBRSg&utm_medium=api&utm_source=c7beb690&v=87FC332A1D074921A50572ACFB9682F227657BA6','2026-03-11'),(2,'Senior Machine Learning Engineer (4 Years Experience)','YMinds.AI','Bangalore, IN','Bangalore','IN',12.20,9.00,'INR','FULLTIME',5,10,'About the Role: Our client is looking for a Senior Machine Learning Engineer to lead the development and deployment of advanced AI systems powering our healthcare copilots and autonomous agents. In this role, you will work with Large Language Models (LLMs), Vision-Language Models (VLMs), and classical NLP systems to solve complex healthcare workflow challenges. You will play a key role in designing and deploying production-grade machine learning systems that help healthcare organizations improv…','adzuna','5661685012','2026-03-13 13:20:22',1,'https://www.adzuna.in/land/ad/5661685012?se=fBNAYt8e8RG_S--KZEBRSg&utm_medium=api&utm_source=c7beb690&v=020E0E472265E7DF6C31B94DE7A04D837CA03F47','2026-03-11'),(3,'Machine Learning Developer','Capgemini Engineering','Bangalore, IN','Bangalore','IN',12.20,9.00,'INR','FULLTIME',5,9,'Machine Learning Developer | 5 To 9 years | Bangalore Technical Expertise: · Solid hands-on experience with machine learning frameworks such as TensorFlow, PyTorch, and Hugging